import{_ as a,c as e,o as t,a4 as o}from"./chunks/framework.BmdFiWrL.js";const b=JSON.parse('{"title":"登录常见问题","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/loginq.md","filePath":"guide/loginq.md","lastUpdated":1780231899000}'),i={name:"guide/loginq.md"},h=o('<h1 id="登录常见问题" tabindex="-1">登录常见问题 <a class="header-anchor" href="#登录常见问题" aria-label="Permalink to &quot;登录常见问题&quot;">​</a></h1><p>v1 之后 Dashboard 使用本地账户登录，并支持将本地账户绑定到 OAuth2 第三方账户。旧版 GitHub OAuth 登录问题不再适用于当前登录流程。</p><h2 id="忘记管理员密码" tabindex="-1">忘记管理员密码 <a class="header-anchor" href="#忘记管理员密码" aria-label="Permalink to &quot;忘记管理员密码&quot;">​</a></h2><p>请参考 <a href="/guide/q13.html">初始化用户密码</a>。重置后建议立即登录后台修改为新的强密码。</p><h2 id="oauth2-登录失败" tabindex="-1">OAuth2 登录失败 <a class="header-anchor" href="#oauth2-登录失败" aria-label="Permalink to &quot;OAuth2 登录失败&quot;">​</a></h2><p>请先确认以下配置：</p><ol><li>Dashboard 配置文件中的 <code>oauth2</code> 字段使用新版结构，详见 <a href="/guide/q14.html">设置 OAuth 2.0 绑定</a>。</li><li>第三方平台的 Callback URL 为 <code>https://你的面板域名/api/v1/oauth2/callback</code>。</li><li>已先使用本地账户登录，并在个人信息页完成 OAuth2 绑定。</li></ol><p>如果还没有绑定关系，不能直接使用 OAuth2 登录到本地账户。</p><h2 id="登录接口被频繁尝试或误封" tabindex="-1">登录接口被频繁尝试或误封 <a class="header-anchor" href="#登录接口被频繁尝试或误封" aria-label="Permalink to &quot;登录接口被频繁尝试或误封&quot;">​</a></h2><p>v1 引入了 Web 应用防火墙，用于限制登录爆破。若 Dashboard 部署在反向代理或 CDN 后面，请正确配置 <a href="/guide/q12.html">前端真实 IP 请求头</a>，否则可能因为无法识别真实访问者 IP 而出现误判。</p><p>如果已经误封，可以使用管理员账户在 <strong>系统设置 → Web 应用防火墙</strong> 中删除对应封禁记录。</p>',11),r=[h];function l(d,n,s,c,u,p){return t(),e("div",null,r)}const m=a(i,[["render",l]]);export{b as __pageData,m as default};
